1	package com.croh.resources;
2	
3	import com.croh.audit.AuditService;
4	import com.croh.rewards.ShippingAddress;
5	import com.croh.rewards.ShippingAddressRepository;
6	import org.springframework.stereotype.Service;
7	import org.springframework.transaction.annotation.Transactional;
8	
9	import java.time.LocalDateTime;
10	import java.util.List;
11	
12	@Service
13	public class ResourceService {
14	
15	    private final UsagePolicyRepository policyRepository;
16	    private final ResourceItemRepository resourceRepository;
17	    private final ClaimRecordRepository claimRecordRepository;
18	    private final DownloadRecordRepository downloadRecordRepository;
19	    private final PrintableNoticeRepository noticeRepository;
20	    private final ShippingAddressRepository addressRepository;
21	    private final AuditService auditService;
22	
23	    public ResourceService(UsagePolicyRepository policyRepository,
24	                           ResourceItemRepository resourceRepository,
25	                           ClaimRecordRepository claimRecordRepository,
26	                           DownloadRecordRepository downloadRecordRepository,
27	                           PrintableNoticeRepository noticeRepository,
28	                           ShippingAddressRepository addressRepository,
29	                           AuditService auditService) {
30	        this.policyRepository = policyRepository;
31	        this.resourceRepository = resourceRepository;
32	        this.claimRecordRepository = claimRecordRepository;
33	        this.downloadRecordRepository = downloadRecordRepository;
34	        this.noticeRepository = noticeRepository;
35	        this.addressRepository = addressRepository;
36	        this.auditService = auditService;
37	    }
38	
39	    @Transactional
40	    public UsagePolicy createPolicy(String name, String scope, int maxActions, int windowDays,
41	                                     String resourceAction, Long actorId, String actorRole) {
42	        UsagePolicy policy = new UsagePolicy();
43	        policy.setName(name);
44	        policy.setScope(scope);
45	        policy.setMaxActions(maxActions);
46	        policy.setWindowDays(windowDays);
47	        policy.setResourceAction(resourceAction);
48	        policy.setCreatedAt(LocalDateTime.now());
49	
50	        UsagePolicy saved = policyRepository.save(policy);
51	
52	        auditService.log(actorId, actorRole, "POLICY_CREATED",
53	                "UsagePolicy", saved.getId().toString(),
54	                null, null, null, null);
55	
56	        return saved;
57	    }
58	
59	    @Transactional
60	    public ResourceItem publishResource(String type, String title, String description,
61	                                         Integer inventoryCount, String fileVersion,
62	                                         Long usagePolicyId, String status,
63	                                         Long actorId, String actorRole) {
64	        ResourceItem item = new ResourceItem();
65	        item.setType(type);
66	        item.setTitle(title);
67	        item.setDescription(description);
68	        item.setInventoryCount(inventoryCount);
69	        item.setFileVersion(fileVersion);
70	        item.setUsagePolicyId(usagePolicyId);
71	        item.setStatus(status != null ? status : "PUBLISHED");
72	        item.setCreatedBy(actorId);
73	        item.setCreatedAt(LocalDateTime.now());
74	        item.setUpdatedAt(LocalDateTime.now());
75	
76	        ResourceItem saved = resourceRepository.save(item);
77	
78	        auditService.log(actorId, actorRole, "RESOURCE_PUBLISHED",
79	                "ResourceItem", saved.getId().toString(),
80	                null, saved.getStatus(), null, null);
81	
82	        return saved;
83	    }
84	
85	    public List<ResourceItem> listResources() {
86	        return resourceRepository.findByStatus("PUBLISHED");
87	    }
88	
89	    public ResourceItem getResource(Long id) {
90	        return resourceRepository.findById(id)
91	                .orElseThrow(() -> new IllegalArgumentException("Resource not found: " + id));
92	    }
93	
94	    /**
95	     * Claims a resource for the given account. Household-scoped limits are enforced
96	     * using the participant's approved primary shipping address as the offline household key.
97	     */
98	    @Transactional
99	    public ClaimResult claimResource(Long resourceId, Long accountId) {
100	        ResourceItem resource = resourceRepository.findById(resourceId)
101	                .orElseThrow(() -> new IllegalArgumentException("Resource not found: " + resourceId));
102	
103	        // Derive household key from primary address
104	        String householdKey = deriveHouseholdKey(accountId);
105	
106	        // Evaluate policy
107	        if (resource.getUsagePolicyId() != null) {
108	            UsagePolicy policy = policyRepository.findById(resource.getUsagePolicyId())
109	                    .orElse(null);
110	            if (policy != null && "CLAIM".equals(policy.getResourceAction())) {
111	                LocalDateTime windowStart = LocalDateTime.now().minusDays(policy.getWindowDays());
112	                long count;
113	                if ("HOUSEHOLD".equals(policy.getScope())) {
114	                    if (householdKey == null) {
115	                        throw new IllegalStateException(
116	                                "Household-scoped policy requires a primary shipping address. Please add an address first.");
117	                    }
118	                    count = claimRecordRepository.countByResourceIdAndHouseholdKeyAndResultAndCreatedAtAfter(
119	                            resourceId, householdKey, "ALLOWED", windowStart);
120	                } else {
121	                    count = claimRecordRepository.countByResourceIdAndAccountIdAndResultAndCreatedAtAfter(
122	                            resourceId, accountId, "ALLOWED", windowStart);
123	                }
124	                if (count >= policy.getMaxActions()) {
125	                    ClaimRecord denied = createClaimRecord(resourceId, accountId, householdKey,
126	                            "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED");
127	                    auditService.log(accountId, null, "RESOURCE_CLAIM_DENIED",
128	                            "ClaimRecord", denied.getId().toString(),
129	                            null, "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED", null);
130	                    return new ClaimResult(denied, null);
131	                }
132	            }
133	        }
134	
135	        // Check inventory
136	        if (resource.getInventoryCount() != null && resource.getInventoryCount() <= 0) {
137	            ClaimRecord denied = createClaimRecord(resourceId, accountId, householdKey,
138	                    "DENIED_POLICY", "OUT_OF_STOCK");
139	            auditService.log(accountId, null, "RESOURCE_CLAIM_DENIED",
140	                    "ClaimRecord", denied.getId().toString(),
141	                    null, "DENIED_POLICY", "OUT_OF_STOCK", null);
142	            return new ClaimResult(denied, null);
143	        }
144	
145	        // Decrement inventory
146	        if (resource.getInventoryCount() != null) {
147	            resource.setInventoryCount(resource.getInventoryCount() - 1);
148	            resource.setUpdatedAt(LocalDateTime.now());
149	            resourceRepository.save(resource);
150	        }
151	
152	        ClaimRecord claim = createClaimRecord(resourceId, accountId, householdKey, "ALLOWED", null);
153	
154	        // Create printable notice
155	        PrintableNotice notice = new PrintableNotice();
156	        notice.setAccountId(accountId);
157	        notice.setResourceId(resourceId);
158	        notice.setNoticeType("CLAIM_CONFIRMATION");
159	        notice.setContent("Resource claimed: " + resource.getTitle() + " (Claim ID: " + claim.getId() + ")");
160	        notice.setCreatedAt(LocalDateTime.now());
161	        PrintableNotice savedNotice = noticeRepository.save(notice);
162	
163	        auditService.log(accountId, null, "RESOURCE_CLAIMED",
164	                "ClaimRecord", claim.getId().toString(),
165	                null, "ALLOWED", null, null);
166	
167	        return new ClaimResult(claim, savedNotice);
168	    }
169	
170	    @Transactional
171	    public DownloadResult downloadResource(Long resourceId, Long accountId, String fileVersion) {
172	        ResourceItem resource = resourceRepository.findById(resourceId)
173	                .orElseThrow(() -> new IllegalArgumentException("Resource not found: " + resourceId));
174	
175	        // Evaluate policy
176	        if (resource.getUsagePolicyId() != null) {
177	            UsagePolicy policy = policyRepository.findById(resource.getUsagePolicyId())
178	                    .orElse(null);
179	            if (policy != null && "DOWNLOAD".equals(policy.getResourceAction())) {
180	                LocalDateTime windowStart = LocalDateTime.now().minusDays(policy.getWindowDays());
181	                long count = downloadRecordRepository.countByResourceIdAndAccountIdAndResultAndCreatedAtAfter(
182	                        resourceId, accountId, "ALLOWED", windowStart);
183	                if (count >= policy.getMaxActions()) {
184	                    DownloadRecord denied = createDownloadRecord(resourceId, accountId, fileVersion,
185	                            "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED");
186	                    auditService.log(accountId, null, "RESOURCE_DOWNLOAD_DENIED",
187	                            "DownloadRecord", denied.getId().toString(),
188	                            null, "DENIED_POLICY", "POLICY_LIMIT_EXCEEDED", null);
189	                    return new DownloadResult(denied);
190	                }
191	            }
192	        }
193	
194	        DownloadRecord record = createDownloadRecord(resourceId, accountId, fileVersion, "ALLOWED", null);
195	
196	        auditService.log(accountId, null, "RESOURCE_DOWNLOADED",
197	                "DownloadRecord", record.getId().toString(),
198	                null, "ALLOWED", null, null);
199	
200	        return new DownloadResult(record);
201	    }
202	
203	    public byte[] getResourceFileContent(Long resourceId, Long accountId) {
204	        List<DownloadRecord> records = downloadRecordRepository.findByResourceIdAndAccountId(resourceId, accountId);
205	        boolean hasAllowed = records.stream().anyMatch(r -> "ALLOWED".equals(r.getResult()));
206	        if (!hasAllowed) {
207	            return null;
208	        }
209	        ResourceItem resource = resourceRepository.findById(resourceId)
210	                .orElseThrow(() -> new IllegalArgumentException("Resource not found"));
211	        String content = "Resource file: " + resource.getTitle() + " (v" + resource.getFileVersion() + ")";
212	        return content.getBytes();
213	    }
214	
215	    public PrintableNotice getNotice(Long noticeId) {
216	        return noticeRepository.findById(noticeId)
217	                .orElseThrow(() -> new IllegalArgumentException("Notice not found: " + noticeId));
218	    }
219	
220	    private ClaimRecord createClaimRecord(Long resourceId, Long accountId, String householdKey,
221	                                           String result, String reasonCode) {
222	        ClaimRecord record = new ClaimRecord();
223	        record.setResourceId(resourceId);
224	        record.setAccountId(accountId);
225	        record.setHouseholdKey(householdKey);
226	        record.setResult(result);
227	        record.setReasonCode(reasonCode);
228	        record.setCreatedAt(LocalDateTime.now());
229	        return claimRecordRepository.save(record);
230	    }
231	
232	    private DownloadRecord createDownloadRecord(Long resourceId, Long accountId, String fileVersion,
233	                                                 String result, String reasonCode) {
234	        DownloadRecord record = new DownloadRecord();
235	        record.setResourceId(resourceId);
236	        record.setAccountId(accountId);
237	        record.setFileVersion(fileVersion);
238	        record.setResult(result);
239	        record.setReasonCode(reasonCode);
240	        record.setCreatedAt(LocalDateTime.now());
241	        return downloadRecordRepository.save(record);
242	    }
243	
244	    /**
245	     * Derives the household key from the participant's primary shipping address.
246	     * Uses normalized city + state + zip as the offline household identifier.
247	     * Returns null if no primary address exists.
248	     */
249	    private String deriveHouseholdKey(Long accountId) {
250	        List<ShippingAddress> addresses = addressRepository.findByAccountId(accountId);
251	        ShippingAddress primary = addresses.stream()
252	                .filter(ShippingAddress::isPrimary)
253	                .findFirst()
254	                .orElse(null);
255	        if (primary == null) {
256	            return null;
257	        }
258	        // Normalize: city (lowercase) + state + zip
259	        return (primary.getCity().toLowerCase().trim() + "|" +
260	                primary.getStateCode().toUpperCase().trim() + "|" +
261	                primary.getZipCode().trim());
262	    }
263	
264	    public record ClaimResult(ClaimRecord claimRecord, PrintableNotice notice) {}
265	    public record DownloadResult(DownloadRecord downloadRecord) {}
266	}
