1	package com.croh.rewards;
2	
3	import jakarta.persistence.Column;
4	import jakarta.persistence.Entity;
5	import jakarta.persistence.GeneratedValue;
6	import jakarta.persistence.GenerationType;
7	import jakarta.persistence.Id;
8	import jakarta.persistence.Table;
9	
10	import java.time.LocalDateTime;
11	
12	@Entity
13	@Table(name = "shipping_address")
14	public class ShippingAddress {
15	
16	    @Id
17	    @GeneratedValue(strategy = GenerationType.IDENTITY)
18	    private Long id;
19	
20	    @Column(name = "account_id", nullable = false)
21	    private Long accountId;
22	
23	    @Column(name = "address_line1_encrypted", nullable = false, columnDefinition = "TEXT")
24	    private String addressLine1Encrypted;
25	
26	    @Column(name = "address_line2_encrypted", columnDefinition = "TEXT")
27	    private String addressLine2Encrypted;
28	
29	    @Column(name = "city", nullable = false, length = 100)
30	    private String city;
31	
32	    @Column(name = "state_code", nullable = false, length = 2)
33	    private String stateCode;
34	
35	    @Column(name = "zip_code", nullable = false, length = 10)
36	    private String zipCode;
37	
38	    @Column(name = "is_primary", nullable = false)
39	    private boolean primary = false;
40	
41	    @Column(name = "created_at", nullable = false, updatable = false)
42	    private LocalDateTime createdAt;
43	
44	    public ShippingAddress() {
45	    }
46	
47	    public Long getId() {
48	        return id;
49	    }
50	
51	    public void setId(Long id) {
52	        this.id = id;
53	    }
54	
55	    public Long getAccountId() {
56	        return accountId;
57	    }
58	
59	    public void setAccountId(Long accountId) {
60	        this.accountId = accountId;
61	    }
62	
63	    public String getAddressLine1Encrypted() {
64	        return addressLine1Encrypted;
65	    }
66	
67	    public void setAddressLine1Encrypted(String addressLine1Encrypted) {
68	        this.addressLine1Encrypted = addressLine1Encrypted;
69	    }
70	
71	    public String getAddressLine2Encrypted() {
72	        return addressLine2Encrypted;
73	    }
74	
75	    public void setAddressLine2Encrypted(String addressLine2Encrypted) {
76	        this.addressLine2Encrypted = addressLine2Encrypted;
77	    }
78	
79	    public String getCity() {
80	        return city;
81	    }
82	
83	    public void setCity(String city) {
84	        this.city = city;
85	    }
86	
87	    public String getStateCode() {
88	        return stateCode;
89	    }
90	
91	    public void setStateCode(String stateCode) {
92	        this.stateCode = stateCode;
93	    }
94	
95	    public String getZipCode() {
96	        return zipCode;
97	    }
98	
99	    public void setZipCode(String zipCode) {
100	        this.zipCode = zipCode;
