98	    @Transactional
99	    public ShippingAddress createAddress(Long accountId, String line1, String line2,
100	                                          String city, String state, String zip) {
101	        if (!STATE_PATTERN.matcher(state).matches()) {
102	            throw new IllegalArgumentException("State must be a 2-character uppercase code");
103	        }
104	        if (!ZIP_PATTERN.matcher(zip).matches()) {
105	            throw new IllegalArgumentException("Zip code must be in 5-digit or 5+4 format");
106	        }
107	
108	        ShippingAddress addr = new ShippingAddress();
109	        addr.setAccountId(accountId);
110	        addr.setAddressLine1Encrypted(encryptionService.encrypt(line1));
111	        addr.setAddressLine2Encrypted(line2 != null ? encryptionService.encrypt(line2) : null);
112	        addr.setCity(city);
113	        addr.setStateCode(state);
114	        addr.setZipCode(zip);
