126	    @Transactional
127	    public RewardOrder placeOrder(Long rewardId, Long accountId, Integer quantity,
128	                                   String fulfillmentType, Long addressId) {
129	        // Validate address ownership if shipping
130	        if (addressId != null) {
131	            ShippingAddress addr = addressRepository.findById(addressId)
132	                    .orElseThrow(() -> new IllegalArgumentException("Address not found: " + addressId));
133	            if (!addr.getAccountId().equals(accountId)) {
134	                throw new SecurityException("Cannot use another user's shipping address");
135	            }
136	        }
137	
138	        RewardItem reward = rewardRepository.findById(rewardId)
139	                .orElseThrow(() -> new IllegalArgumentException("Reward not found: " + rewardId));
140	
141	        int qty = quantity != null ? quantity : 1;
142	
143	        // Check per-user limit
144	        long existingOrders = orderRepository.countByRewardIdAndAccountId(rewardId, accountId);
145	        if (existingOrders + qty > reward.getPerUserLimit()) {
146	            throw new IllegalStateException("Per-user limit exceeded for this reward");
147	        }
148	
149	        // Check inventory
150	        if (reward.getInventoryCount() < qty) {
151	            throw new IllegalStateException("Insufficient inventory for this reward");
152	        }
153	
154	        // Decrement inventory
155	        reward.setInventoryCount(reward.getInventoryCount() - qty);
156	        reward.setUpdatedAt(LocalDateTime.now());
157	        rewardRepository.save(reward);
158	
159	        RewardOrder order = new RewardOrder();
160	        order.setRewardId(rewardId);
161	        order.setAccountId(accountId);
162	        order.setQuantity(qty);
163	        order.setFulfillmentType(fulfillmentType != null ? fulfillmentType : reward.getFulfillmentType());
164	        order.setShippingAddressId(addressId);
165	        order.setStatus("ORDERED");
166	        order.setCreatedAt(LocalDateTime.now());
167	        order.setUpdatedAt(LocalDateTime.now());
168	
169	        RewardOrder saved = orderRepository.save(order);
170	
171	        auditService.log(accountId, null, "ORDER_PLACED",
172	                "RewardOrder", saved.getId().toString(),
173	                null, "ORDERED", null, null);
174	
175	        return saved;
176	    }
