178	    @Transactional
179	    public RewardOrder transitionOrder(Long orderId, String toState, String note,
180	                                        Long actorId, String actorRole) {
181	        RewardOrder order = orderRepository.findById(orderId)
182	                .orElseThrow(() -> new IllegalArgumentException("Order not found: " + orderId));
183	
184	        String beforeState = order.getStatus();
185	        Map<String, Set<String>> transitions = "VOUCHER".equals(order.getFulfillmentType())
186	                ? VOUCHER_TRANSITIONS : PHYSICAL_TRANSITIONS;
187	
188	        Set<String> allowedNext = transitions.get(beforeState);
189	        if (allowedNext == null || !allowedNext.contains(toState)) {
190	            throw new IllegalStateException(
191	                    "Invalid transition from " + beforeState + " to " + toState);
192	        }
193	
194	        order.setStatus(toState);
195	        if (note != null) order.setNote(note);
196	        order.setUpdatedAt(LocalDateTime.now());
197	
198	        RewardOrder saved = orderRepository.save(order);
199	
200	        auditService.log(actorId, actorRole, "ORDER_TRANSITIONED",
201	                "RewardOrder", saved.getId().toString(),
202	                beforeState, toState, null, null);
203	
204	        return saved;
205	    }
