252	    @Transactional
253	    public FulfillmentException transitionException(Long exceptionId, String toState,
254	                                                     Long actorId, String actorRole) {
255	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
256	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
257	
258	        String beforeState = exc.getStatus();
259	        Set<String> allowedNext = EXCEPTION_TRANSITIONS.get(beforeState);
260	        if (allowedNext == null || !allowedNext.contains(toState)) {
261	            throw new IllegalStateException(
262	                    "Invalid transition from " + beforeState + " to " + toState);
263	        }
264	
265	        exc.setStatus(toState);
266	        if ("RESOLVED".equals(toState) || "REJECTED".equals(toState)) {
267	            exc.setResolvedBy(actorId);
268	        }
269	        exc.setUpdatedAt(LocalDateTime.now());
270	
271	        FulfillmentException saved = exceptionRepository.save(exc);
272	
273	        auditService.log(actorId, actorRole, "EXCEPTION_TRANSITIONED",
274	                "FulfillmentException", saved.getId().toString(),
275	                beforeState, toState, null, null);
276	
277	        return saved;
278	    }
