280	    @Transactional
281	    public FulfillmentException reopenException(Long exceptionId, String reasonCode, String note,
282	                                                 Long actorId, String actorRole) {
283	        FulfillmentException exc = exceptionRepository.findById(exceptionId)
284	                .orElseThrow(() -> new IllegalArgumentException("Exception not found: " + exceptionId));
285	
286	        if (!"RESOLVED".equals(exc.getStatus()) && !"REJECTED".equals(exc.getStatus())) {
287	            throw new IllegalStateException("Can only reopen from RESOLVED or REJECTED state");
288	        }
289	
290	        String beforeState = exc.getStatus();
291	        exc.setStatus("OPEN");
292	        exc.setReopenReason(note);
293	        exc.setSupervisorApproval(true);
294	        exc.setResolvedBy(null);
295	        exc.setUpdatedAt(LocalDateTime.now());
296	
297	        FulfillmentException saved = exceptionRepository.save(exc);
298	
299	        auditService.log(actorId, actorRole, "EXCEPTION_REOPENED",
300	                "FulfillmentException", saved.getId().toString(),
301	                beforeState, "OPEN", reasonCode, null);
302	
303	        return saved;
304	    }
