68	                                          String filters, String format, Long actorId) {
69	        ReportTemplate template = new ReportTemplate();
70	        template.setName(name);
71	        template.setDescription(description);
72	        template.setMetricIds(metricIds);
73	        template.setDefaultFilters(filters);
