81	    @Transactional
82	    public ReportExecution executeReport(Long templateId, String filters, String format,
83	                                          Long actorId) {
84	        ReportTemplate template = templateRepository.findById(templateId)
85	                .orElseThrow(() -> new IllegalArgumentException("Template not found: " + templateId));
86	
87	        ReportExecution execution = new ReportExecution();
88	        execution.setTemplateId(templateId);
89	        execution.setFilters(filters);
90	        execution.setOutputFormat(format != null ? format : template.getOutputFormat());
91	        execution.setStatus("PENDING");
92	        execution.setExecutedBy(actorId);
93	        execution.setCreatedAt(LocalDateTime.now());
94	
95	        // Execute real metrics from the template's configured metric IDs
96	        List<String> headers = List.of("metric_name", "query", "result_value");
97	        List<List<String>> rows = new ArrayList<>();
98	
99	        String metricIdsStr = template.getMetricIds();
100	        if (metricIdsStr != null && !metricIdsStr.isBlank()) {
101	            for (String idStr : metricIdsStr.split(",")) {
102	                try {
103	                    Long metricId = Long.parseLong(idStr.trim());
104	                    metricRepository.findById(metricId).ifPresent(metric -> {
105	                        String queryTemplate = metric.getQueryTemplate();
106	                        try {
107	                            // Execute the metric query with optional filters
108	                            Query query = entityManager.createNativeQuery(queryTemplate);
109	                            Object result = query.getSingleResult();
110	                            rows.add(List.of(metric.getName(), queryTemplate, String.valueOf(result)));
111	                        } catch (Exception e) {
112	                            rows.add(List.of(metric.getName(), queryTemplate, "ERROR: " + e.getMessage()));
113	                        }
114	                    });
115	                } catch (NumberFormatException ignored) {
116	                    // skip invalid metric IDs
117	                }
118	            }
119	        }
120	
121	        if (rows.isEmpty()) {
122	            rows.add(List.of("(no metrics)", "", "0"));
123	        }
124	
125	        StringBuilder csv = new StringBuilder();
126	        csv.append(String.join(",", headers)).append("\n");
127	        for (List<String> row : rows) {
128	            csv.append(String.join(",", row)).append("\n");
129	        }
130	
131	        // Write to local file artifact
132	        String exportPath;
133	        String outputFormat = execution.getOutputFormat();
134	        if ("PDF".equalsIgnoreCase(outputFormat)) {
135	            exportPath = exportService.exportPdf("Report: " + template.getName(), headers, rows, "report-" + template.getId());
136	        } else {
137	            exportPath = exportService.exportCsv(csv.toString(), "report-" + template.getId());
138	        }
139	
140	        execution.setResultData(csv.toString());
141	        execution.setExportFilePath(exportPath);
142	        execution.setStatus("COMPLETED");
143	        execution.setCompletedAt(LocalDateTime.now());
144	
145	        ReportExecution saved = executionRepository.save(execution);
146	
147	        auditService.log(actorId, null, "REPORT_EXPORTED",
148	                "ReportExecution", saved.getId().toString(),
149	                null, "COMPLETED", null, null);
150	
151	        return saved;
152	    }
