163	    public Map<String, Object> getDataQuality(String domain, LocalDateTime from, LocalDateTime to) {
164	        Map<String, Object> quality = new LinkedHashMap<>();
165	
166	        if ("events".equals(domain) || domain == null) {
167	            quality.put("events_missing_description", countNullField("event", "description", from, to));
168	            quality.put("events_missing_location", countNullField("event", "location", from, to));
169	        }
170	
171	        if ("resources".equals(domain) || domain == null) {
172	            quality.put("resources_missing_description", countNullField("resource_item", "description", from, to));
173	        }
174	
175	        if ("rewards".equals(domain) || domain == null) {
176	            quality.put("rewards_missing_description", countNullField("reward_item", "description", from, to));
177	        }
178	
179	        // Duplicate detection counts
180	        if ("verification".equals(domain) || domain == null) {
181	            quality.put("credential_duplicates", countDuplicates(from, to));
182	        }
183	
184	        // Anomaly: accounts with excessive failed login attempts
185	        if ("accounts".equals(domain) || domain == null) {
186	            quality.put("accounts_with_high_failed_logins", countHighFailedLogins(from, to));
187	        }
188	
189	        return quality;
190	    }
191	
192	    private long countDuplicates(LocalDateTime from, LocalDateTime to) {
193	        String sql = "SELECT COUNT(*) FROM org_credential_document " +
194	                "WHERE duplicate_checksum_flag = true AND created_at BETWEEN :from AND :to";
195	        Query query = entityManager.createNativeQuery(sql);
196	        query.setParameter("from", from);
197	        query.setParameter("to", to);
198	        return ((Number) query.getSingleResult()).longValue();
199	    }
200	
201	    private long countHighFailedLogins(LocalDateTime from, LocalDateTime to) {
202	        String sql = "SELECT COUNT(*) FROM account " +
203	                "WHERE failed_login_attempts >= 5 AND updated_at BETWEEN :from AND :to";
204	        Query query = entityManager.createNativeQuery(sql);
205	        query.setParameter("from", from);
206	        query.setParameter("to", to);
207	        return ((Number) query.getSingleResult()).longValue();
208	    }
209	
210	    private long countNullField(String table, String field, LocalDateTime from, LocalDateTime to) {
211	        String sql = "SELECT COUNT(*) FROM " + table +
212	                " WHERE " + field + " IS NULL AND created_at BETWEEN :from AND :to";
213	        Query query = entityManager.createNativeQuery(sql);
214	        query.setParameter("from", from);
215	        query.setParameter("to", to);
216	        return ((Number) query.getSingleResult()).longValue();
217	    }
218	}
