28	        // Object-level authorization: notice must belong to the requesting user
29	        if (!notice.getAccountId().equals(actor.accountId())) {
30	            return ResponseEntity.status(403).build();
31	        }
32	        return ResponseEntity.ok(Map.of(
33	                "id", notice.getId(),
34	                "noticeType", notice.getNoticeType(),
35	                "content", notice.getContent(),
36	                "createdAt", notice.getCreatedAt().toString()
37	        ));
38	    }
39	
40	    private SessionAccount getSessionAccount() {
41	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
42	        return (SessionAccount) auth.getPrincipal();
43	    }
44	}
