1	package com.croh.reporting;
2	
3	import jakarta.persistence.EntityManager;
4	import jakarta.persistence.Query;
5	import org.springframework.stereotype.Service;
6	
7	import java.time.LocalDateTime;
8	import java.util.LinkedHashMap;
9	import java.util.Map;
10	
11	@Service
12	public class AnalyticsService {
13	
14	    private final EntityManager entityManager;
15	
16	    public AnalyticsService(EntityManager entityManager) {
17	        this.entityManager = entityManager;
18	    }
19	
20	    public Map<String, Object> getOperationsSummary(LocalDateTime from, LocalDateTime to,
21	                                                      String orgId) {
22	        Map<String, Object> summary = new LinkedHashMap<>();
23	
24	        // Registration counts
25	        summary.put("totalRegistrations", countRegistrations(from, to, null));
26	        summary.put("approvedRegistrations", countRegistrations(from, to, "APPROVED"));
27	        summary.put("cancelledRegistrations", countRegistrations(from, to, "CANCELLED"));
28	        summary.put("waitlistedRegistrations", countRegistrations(from, to, "WAITLISTED"));
29	
30	        // Claim counts
31	        summary.put("totalClaims", countClaims(from, to));
32	        summary.put("allowedClaims", countClaimsByResult(from, to, "ALLOWED"));
33	        summary.put("deniedClaims", countClaimsByResult(from, to, "DENIED_POLICY"));
34	
35	        // Order counts
36	        summary.put("totalOrders", countOrders(from, to));
37	        summary.put("deliveredOrders", countOrdersByStatus(from, to, "DELIVERED"));
38	        summary.put("redeemedOrders", countOrdersByStatus(from, to, "REDEEMED"));
39	
40	        // Completion rates
41	        long totalRegs = (long) summary.get("totalRegistrations");
42	        long approvedRegs = (long) summary.get("approvedRegistrations");
43	        summary.put("registrationApprovalRate",
44	                totalRegs > 0 ? (double) approvedRegs / totalRegs : 0.0);
45	
46	        long totalOrders = (long) summary.get("totalOrders");
47	        long completedOrders = (long) summary.get("deliveredOrders") + (long) summary.get("redeemedOrders");
48	        summary.put("orderCompletionRate",
49	                totalOrders > 0 ? (double) completedOrders / totalOrders : 0.0);
50	
51	        return summary;
52	    }
53	
54	    private long countRegistrations(LocalDateTime from, LocalDateTime to, String status) {
55	        StringBuilder sql = new StringBuilder(
56	                "SELECT COUNT(*) FROM event_registration WHERE created_at BETWEEN :from AND :to");
57	        if (status != null) {
58	            sql.append(" AND status = :status");
59	        }
60	        Query query = entityManager.createNativeQuery(sql.toString());
61	        query.setParameter("from", from);
62	        query.setParameter("to", to);
63	        if (status != null) {
64	            query.setParameter("status", status);
65	        }
66	        return ((Number) query.getSingleResult()).longValue();
67	    }
68	
69	    private long countClaims(LocalDateTime from, LocalDateTime to) {
70	        Query query = entityManager.createNativeQuery(
71	                "SELECT COUNT(*) FROM claim_record WHERE created_at BETWEEN :from AND :to");
72	        query.setParameter("from", from);
73	        query.setParameter("to", to);
74	        return ((Number) query.getSingleResult()).longValue();
75	    }
76	
77	    private long countClaimsByResult(LocalDateTime from, LocalDateTime to, String result) {
78	        Query query = entityManager.createNativeQuery(
79	                "SELECT COUNT(*) FROM claim_record WHERE created_at BETWEEN :from AND :to AND result = :result");
80	        query.setParameter("from", from);
81	        query.setParameter("to", to);
82	        query.setParameter("result", result);
83	        return ((Number) query.getSingleResult()).longValue();
84	    }
85	
86	    private long countOrders(LocalDateTime from, LocalDateTime to) {
87	        Query query = entityManager.createNativeQuery(
88	                "SELECT COUNT(*) FROM reward_order WHERE created_at BETWEEN :from AND :to");
89	        query.setParameter("from", from);
90	        query.setParameter("to", to);
91	        return ((Number) query.getSingleResult()).longValue();
92	    }
93	
94	    private long countOrdersByStatus(LocalDateTime from, LocalDateTime to, String status) {
95	        Query query = entityManager.createNativeQuery(
96	                "SELECT COUNT(*) FROM reward_order WHERE created_at BETWEEN :from AND :to AND status = :status");
97	        query.setParameter("from", from);
98	        query.setParameter("to", to);
99	        query.setParameter("status", status);
100	        return ((Number) query.getSingleResult()).longValue();
101	    }
102	}
