24	
25	@RestController
26	@RequestMapping("/api/v1/resources")
27	public class ResourceController {
28	
29	    private final ResourceService resourceService;
30	
31	    public ResourceController(ResourceService resourceService) {
32	        this.resourceService = resourceService;
33	    }
34	
35	    @PostMapping
36	    @RequirePermission(Permission.PUBLISH_RESOURCE)
37	    public ResponseEntity<ResourceResponse> publishResource(@Valid @RequestBody ResourceRequest request) {
38	        SessionAccount actor = getSessionAccount();
39	        ResourceItem item = resourceService.publishResource(
40	                request.type(), request.title(), request.description(),
41	                request.inventoryCount(), request.fileVersion(), request.usagePolicyId(),
42	                request.status(), actor.accountId(), actor.activeRole().name());
43	        return ResponseEntity.status(201).body(toResponse(item));
44	    }
45	
46	    @GetMapping
47	    public ResponseEntity<List<ResourceResponse>> listResources() {
48	        List<ResourceResponse> resources = resourceService.listResources().stream()
49	                .map(this::toResponse)
50	                .toList();
51	        return ResponseEntity.ok(resources);
52	    }
53	
54	    @GetMapping("/{id}")
55	    public ResponseEntity<ResourceResponse> getResource(@PathVariable Long id) {
56	        ResourceItem item = resourceService.getResource(id);
57	        return ResponseEntity.ok(toResponse(item));
58	    }
59	
60	    @PostMapping("/{id}/claim")
61	    public ResponseEntity<ClaimResponse> claimResource(@PathVariable Long id) {
62	        SessionAccount actor = getSessionAccount();
63	        ResourceService.ClaimResult result = resourceService.claimResource(
64	                id, actor.accountId());
65	        ClaimRecord claim = result.claimRecord();
66	        Long noticeId = result.notice() != null ? result.notice().getId() : null;
67	        return ResponseEntity.ok(new ClaimResponse(claim.getId(), claim.getResult(),
68	                claim.getReasonCode(), noticeId));
69	    }
70	
71	    @PostMapping("/files/{id}/download")
72	    public ResponseEntity<DownloadResponse> downloadResource(@PathVariable Long id,
73	                                                              @RequestBody DownloadRequest request) {
74	        SessionAccount actor = getSessionAccount();
75	        ResourceService.DownloadResult result = resourceService.downloadResource(
76	                id, actor.accountId(), request.fileVersion());
77	        DownloadRecord record = result.downloadRecord();
78	        return ResponseEntity.ok(new DownloadResponse(record.getId(), record.getResult(),
79	                record.getReasonCode()));
80	    }
81	
82	    @GetMapping("/{id}/file")
83	    public ResponseEntity<byte[]> getResourceFile(@PathVariable Long id) {
84	        SessionAccount actor = getSessionAccount();
85	        ResourceItem resource = resourceService.getResource(id);
86	        if (!"DOWNLOADABLE_FILE".equals(resource.getType())) {
87	            return ResponseEntity.badRequest().build();
88	        }
89	        // Verify the user has a successful download record for this resource
90	        byte[] fileData = resourceService.getResourceFileContent(id, actor.accountId());
91	        if (fileData == null) {
92	            return ResponseEntity.status(403).build();
93	        }
94	        return ResponseEntity.ok()
95	                .header("Content-Type", "application/octet-stream")
96	                .header("Content-Disposition", "attachment; filename=\"resource-" + id + "\"")
97	                .body(fileData);
98	    }
99	
100	    private ResourceResponse toResponse(ResourceItem r) {
101	        return new ResourceResponse(r.getId(), r.getType(), r.getTitle(), r.getDescription(),
102	                r.getInventoryCount(), r.getFileVersion(), r.getUsagePolicyId(),
103	                r.getStatus(), r.getCreatedBy(), r.getCreatedAt(), r.getUpdatedAt());
104	    }
105	
106	    private SessionAccount getSessionAccount() {
107	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
108	        return (SessionAccount) auth.getPrincipal();
109	    }
110	}
