5	import com.croh.security.Permission;
6	import com.croh.security.RequirePermission;
7	import com.croh.security.SessionAccount;
8	import jakarta.validation.Valid;
9	import org.springframework.http.ResponseEntity;
10	import org.springframework.security.core.Authentication;
11	import org.springframework.security.core.context.SecurityContextHolder;
12	import org.springframework.web.bind.annotation.GetMapping;
13	import org.springframework.web.bind.annotation.PathVariable;
14	import org.springframework.web.bind.annotation.PostMapping;
15	import org.springframework.web.bind.annotation.RequestBody;
16	import org.springframework.web.bind.annotation.RequestMapping;
17	import org.springframework.web.bind.annotation.RestController;
18	
19	import java.util.List;
20	
21	@RestController
22	@RequestMapping("/api/v1/rewards")
23	public class RewardController {
24	
25	    private final RewardService rewardService;
26	
27	    public RewardController(RewardService rewardService) {
28	        this.rewardService = rewardService;
29	    }
30	
31	    @PostMapping
32	    @RequirePermission(Permission.MANAGE_REWARDS)
33	    public ResponseEntity<RewardResponse> createReward(@Valid @RequestBody RewardRequest request) {
34	        SessionAccount actor = getSessionAccount();
35	        RewardItem item = rewardService.createReward(
36	                request.title(), request.description(), request.tier(),
37	                request.inventoryCount(), request.perUserLimit(),
38	                request.fulfillmentType(), request.status(),
39	                actor.accountId(), actor.activeRole().name());
40	        return ResponseEntity.status(201).body(toResponse(item));
41	    }
42	
43	    @GetMapping
44	    public ResponseEntity<List<RewardResponse>> listRewards() {
45	        List<RewardResponse> rewards = rewardService.listRewards().stream()
46	                .map(this::toResponse)
47	                .toList();
48	        return ResponseEntity.ok(rewards);
49	    }
50	
51	    @GetMapping("/{id}")
52	    public ResponseEntity<RewardResponse> getReward(@PathVariable Long id) {
53	        RewardItem item = rewardService.getReward(id);
54	        return ResponseEntity.ok(toResponse(item));
55	    }
56	
57	    private RewardResponse toResponse(RewardItem r) {
58	        return new RewardResponse(r.getId(), r.getTitle(), r.getDescription(), r.getTier(),
59	                r.getInventoryCount(), r.getPerUserLimit(), r.getFulfillmentType(),
60	                r.getStatus(), r.getCreatedBy(), r.getCreatedAt(), r.getUpdatedAt());
61	    }
62	
63	    private SessionAccount getSessionAccount() {
64	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
65	        return (SessionAccount) auth.getPrincipal();
66	    }
67	}
