9	public final class RolePermissions {
10	
11	    private static final Map<RoleType, Set<Permission>> ROLE_PERMISSION_MAP;
12	
13	    static {
14	        Map<RoleType, Set<Permission>> map = new EnumMap<>(RoleType.class);
15	
16	        map.put(RoleType.ADMIN, Collections.unmodifiableSet(EnumSet.allOf(Permission.class)));
17	
18	        map.put(RoleType.ORG_OPERATOR, Collections.unmodifiableSet(EnumSet.of(
19	                Permission.PUBLISH_EVENT,
20	                Permission.REVIEW_REGISTRATION,
21	                Permission.PUBLISH_RESOURCE,
22	                Permission.MANAGE_RESOURCE_POLICY,
23	                Permission.MANAGE_REWARDS,
24	                Permission.MANAGE_REWARD_FULFILLMENT,
25	                Permission.CONFIGURE_ALERT_RULES,
26	                Permission.EXPORT_REPORTS
27	        )));
28	
29	        map.put(RoleType.VOLUNTEER, Collections.unmodifiableSet(EnumSet.of(
30	                Permission.REVIEW_REGISTRATION,
31	                Permission.REVIEW_VERIFICATION
32	        )));
33	
34	        map.put(RoleType.PARTICIPANT, Collections.unmodifiableSet(EnumSet.of(
35	                Permission.SELF_SERVICE
36	        )));
37	
38	        ROLE_PERMISSION_MAP = Collections.unmodifiableMap(map);
39	    }
40	
41	    private RolePermissions() {
42	        // utility class
43	    }
44	
45	    public static Set<Permission> getPermissions(RoleType roleType) {
46	        return ROLE_PERMISSION_MAP.getOrDefault(roleType, Collections.emptySet());
47	    }
48	}
