        List<DownloadRecord> records = downloadRecordRepository.findByResourceIdAndAccountId(resourceId, accountId);
        boolean hasAllowed = records.stream().anyMatch(r -> "ALLOWED".equals(r.getResult()));
        if (!hasAllowed) {
            return null;
        }
        ResourceItem resource = resourceRepository.findById(resourceId)
                .orElseThrow(() -> new IllegalArgumentException("Resource not found"));

        // Read actual file bytes from local disk storage
        if (resource.getFilePath() != null) {
            try {
                java.nio.file.Path path = java.nio.file.Paths.get(resource.getFilePath());
                return java.nio.file.Files.readAllBytes(path);
            } catch (java.io.IOException e) {
                throw new IllegalStateException("Failed to read resource file: " + e.getMessage(), e);
            }
        }

        // Fallback for legacy resources without file_path (should not happen for new resources)
        return null;
    }"}

