1	<script setup lang="ts">
2	import { ref, onMounted } from 'vue'
3	import apiClient from '@/api/client'
4	import type { VerificationQueueItem } from '@/types'
5	
6	interface QueueItemState {
7	  decision: string
8	  reasonCode: string
9	  reviewNote: string
10	  state: 'idle' | 'loading' | 'success' | 'error'
11	  error: string
12	}
13	
14	const items = ref<VerificationQueueItem[]>([])
15	const itemStates = ref<Map<number, QueueItemState>>(new Map())
16	const loadState = ref<'idle' | 'loading' | 'success' | 'error'>('idle')
17	const loadError = ref('')
18	
19	function getItemState(id: number): QueueItemState {
20	  if (!itemStates.value.has(id)) {
21	    itemStates.value.set(id, { decision: 'APPROVE', reasonCode: '', reviewNote: '', state: 'idle', error: '' })
22	  }
23	  return itemStates.value.get(id)!
24	}
25	
26	async function fetchQueue() {
27	  loadState.value = 'loading'
28	  try {
29	    const response = await apiClient.get<VerificationQueueItem[]>('/admin/verification/queue')
30	    items.value = response.data
31	    loadState.value = 'success'
32	  } catch (err: any) {
33	    loadError.value = err.response?.data?.message || 'Failed to load queue.'
34	    loadState.value = 'error'
35	  }
36	}
37	
38	async function submitDecision(item: VerificationQueueItem) {
39	  const s = getItemState(item.id)
40	  s.state = 'loading'
41	  s.error = ''
42	  const endpoint = item.type === 'PERSON'
43	    ? `/admin/verification/person/${item.id}/decision`
44	    : `/admin/verification/org-document/${item.id}/decision`
45	  try {
46	    await apiClient.post(endpoint, {
