        auditLogRepository.deleteAll();
        noticeRepository.deleteAll();
        claimRecordRepository.deleteAll();
        downloadRecordRepository.deleteAll();
        resourceRepository.deleteAll();
        policyRepository.deleteAll();
        accountRepository.deleteAll();
        orgUser = createAccount("orguser");
        participant = createAccount("participant");

        // Create a temp file to serve as the resource file
        tempFile = Files.createTempFile("resource-test-", ".pdf");
        Files.write(tempFile, "PDF-test-content-bytes".getBytes());
    }

    @AfterEach
    void tearDown() throws IOException {
        if (tempFile != null) {
            Files.deleteIfExists(tempFile);
        }
    }

