        // Create a resource with file_path pointing to temp file
        ResourceItem r = new ResourceItem();
        r.setType("DOWNLOADABLE_FILE");
        r.setTitle("Storm Guide");
        r.setFileVersion("v1");
        r.setFilePath(tempFile.toAbsolutePath().toString());
        r.setFileSize(Files.size(tempFile));
        r.setContentType("application/pdf");
        r.setStatus("PUBLISHED");
        r.setCreatedBy(orgUser.getId());
        r.setCreatedAt(LocalDateTime.now());
        r.setUpdatedAt(LocalDateTime.now());
