61	    @PostMapping("/register")
62	    public ResponseEntity<RegisterResponse> register(@Valid @RequestBody RegisterRequest request) {
63	        String normalizedUsername = request.username().toLowerCase();
64	
65	        if (accountRepository.findByUsername(normalizedUsername).isPresent()) {
66	            throw new DuplicateException("Username is already taken");
67	        }
68	
69	        LocalDateTime now = LocalDateTime.now();
70	
71	        Account account = new Account();
72	        account.setUsername(normalizedUsername);
73	        account.setPasswordHash(passwordEncoder.encode(request.password()));
74	        account.setAccountType(request.accountType());
75	        account.setStatus(Account.AccountStatus.ACTIVE);
76	        account.setFailedLoginAttempts(0);
77	        account.setCreatedAt(now);
78	        account.setUpdatedAt(now);
79	        accountRepository.save(account);
80	
81	        auditService.log(account.getId(), "SYSTEM", "ACCOUNT_REGISTERED",
82	                "ACCOUNT", account.getId().toString(),
83	                null, "ACTIVE",
84	                null, UUID.randomUUID().toString());
85	
86	        RegisterResponse response = new RegisterResponse(
87	                account.getId(),
88	                account.getUsername(),
89	                account.getStatus().name(),
90	                now.toInstant(ZoneOffset.UTC)
91	        );
92	        return ResponseEntity.status(201).body(response);
93	    }
