95	    @PostMapping("/login")
96	    public ResponseEntity<?> login(@Valid @RequestBody LoginRequest request,
97	                                   HttpServletRequest httpRequest) {
98	        SessionAccount session = authService.login(request.username(), request.password());
99	
100	        // Always create the session — blacklisted users get a constrained session
101	        // that only allows appeal submission (enforced by BlacklistEnforcementFilter)
102	        HttpSession httpSession = httpRequest.getSession(true);
103	        httpSession.setAttribute(SESSION_ACCOUNT_KEY, session);
104	
105	        if ("BLACKLISTED".equals(session.accountStatus())) {
106	            // Return 423 per API spec, but the session cookie IS set so appeal endpoints work
107	            BlacklistRecord record = blacklistRecordRepository
108	                    .findTopByAccountIdOrderByCreatedAtDesc(session.accountId())
109	                    .orElse(null);
110	
111	            ErrorResponse error = new ErrorResponse(
112	                    "ACCOUNT_BLACKLISTED",
113	                    "Account has been blacklisted. You may submit an appeal.",
114	                    List.of(),
115	                    UUID.randomUUID().toString(),
116	                    Instant.now()
117	            );
118	            return ResponseEntity.status(423).body(error);
119	        }
120	
121	        return ResponseEntity.ok(buildLoginResponse(session));
122	    }
123	
124	    @PostMapping("/logout")
125	    public ResponseEntity<Void> logout(HttpServletRequest request) {
126	        HttpSession session = request.getSession(false);
127	        if (session != null) {
128	            session.invalidate();
129	        }
130	        SecurityContextHolder.clearContext();
131	        return ResponseEntity.noContent().build();
132	    }
133	
134	    @GetMapping("/me")
135	    public ResponseEntity<LoginResponse> me() {
136	        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
137	        if (auth == null || !(auth.getPrincipal() instanceof SessionAccount session)) {
138	            return ResponseEntity.status(401).build();
139	        }
140	        return ResponseEntity.ok(buildLoginResponse(session));
141	    }
142	
143	    private LoginResponse buildLoginResponse(SessionAccount session) {
144	        List<String> approvedRoles = authService.getApprovedRoleNames(session.accountId());
145	        Set<String> permissionNames = session.permissions().stream()
146	                .map(Permission::name)
147	                .collect(Collectors.toSet());
148	
149	        return new LoginResponse(
150	                session.accountId(),
151	                session.username(),
152	                approvedRoles,
153	                session.activeRole().name(),
154	                permissionNames
155	        );
156	    }
157	}
