1	package com.croh.crypto;
2	
3	import org.springframework.beans.factory.annotation.Value;
4	import org.springframework.stereotype.Service;
5	
6	import javax.crypto.Cipher;
7	import javax.crypto.SecretKey;
8	import javax.crypto.spec.GCMParameterSpec;
9	import javax.crypto.spec.SecretKeySpec;
10	import java.nio.charset.StandardCharsets;
11	import java.security.SecureRandom;
12	import java.util.Base64;
13	
14	/**
15	 * AES-GCM encryption service for sensitive fields and file blobs.
16	 * The key is derived from the CROH_ENCRYPTION_KEY environment variable.
17	 */
18	@Service
19	public class EncryptionService {
20	
21	    private static final String ALGORITHM = "AES/GCM/NoPadding";
22	    private static final int GCM_IV_LENGTH = 12;
23	    private static final int GCM_TAG_LENGTH = 128;
24	    private final SecretKey secretKey;
25	    private final SecureRandom secureRandom = new SecureRandom();
26	
27	    public EncryptionService(@Value("${croh.encryption.key:}") String keyMaterial,
28	                             @Value("${spring.profiles.active:}") String activeProfile) {
29	        if (keyMaterial == null || keyMaterial.isBlank()) {
30	            if (activeProfile != null && activeProfile.contains("test")) {
31	                keyMaterial = "test-key-for-unit-tests-only-00";
32	            } else {
33	                throw new IllegalStateException(
34	                    "croh.encryption.key must be set in non-test profiles. " +
35	                    "Set via environment variable CROH_ENCRYPTION_KEY or application properties.");
36	            }
37	        }
38	        // Derive a 256-bit key by hashing or truncating/padding the key material
39	        byte[] keyBytes = new byte[32];
40	        byte[] raw = keyMaterial.getBytes(StandardCharsets.UTF_8);
41	        System.arraycopy(raw, 0, keyBytes, 0, Math.min(raw.length, 32));
42	        this.secretKey = new SecretKeySpec(keyBytes, "AES");
43	    }
44	
45	    /**
46	     * Encrypts a plaintext string. Returns Base64-encoded ciphertext (IV prepended).
47	     */
48	    public String encrypt(String plaintext) {
49	        if (plaintext == null) return null;
50	        try {
51	            byte[] iv = new byte[GCM_IV_LENGTH];
52	            secureRandom.nextBytes(iv);
53	
54	            Cipher cipher = Cipher.getInstance(ALGORITHM);
55	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
56	
57	            byte[] ciphertext = cipher.doFinal(plaintext.getBytes(StandardCharsets.UTF_8));
58	
59	            // Prepend IV to ciphertext
60	            byte[] combined = new byte[iv.length + ciphertext.length];
61	            System.arraycopy(iv, 0, combined, 0, iv.length);
62	            System.arraycopy(ciphertext, 0, combined, iv.length, ciphertext.length);
63	
64	            return Base64.getEncoder().encodeToString(combined);
65	        } catch (Exception e) {
66	            throw new RuntimeException("Encryption failed", e);
67	        }
68	    }
69	
70	    /**
71	     * Decrypts a Base64-encoded ciphertext (IV prepended). Returns plaintext string.
72	     */
73	    public String decrypt(String encrypted) {
74	        if (encrypted == null) return null;
75	        try {
76	            byte[] combined = Base64.getDecoder().decode(encrypted);
77	
78	            byte[] iv = new byte[GCM_IV_LENGTH];
79	            byte[] ciphertext = new byte[combined.length - GCM_IV_LENGTH];
80	            System.arraycopy(combined, 0, iv, 0, GCM_IV_LENGTH);
81	            System.arraycopy(combined, GCM_IV_LENGTH, ciphertext, 0, ciphertext.length);
82	
83	            Cipher cipher = Cipher.getInstance(ALGORITHM);
84	            cipher.init(Cipher.DECRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
85	
86	            byte[] plainBytes = cipher.doFinal(ciphertext);
87	            return new String(plainBytes, StandardCharsets.UTF_8);
88	        } catch (Exception e) {
89	            throw new RuntimeException("Decryption failed", e);
90	        }
91	    }
92	
93	    /**
94	     * Encrypts raw bytes. Returns encrypted bytes (IV prepended).
95	     */
96	    public byte[] encryptBytes(byte[] plainBytes) {
97	        if (plainBytes == null) return null;
98	        try {
99	            byte[] iv = new byte[GCM_IV_LENGTH];
100	            secureRandom.nextBytes(iv);
101	
102	            Cipher cipher = Cipher.getInstance(ALGORITHM);
103	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
104	
105	            byte[] ciphertext = cipher.doFinal(plainBytes);
106	
107	            byte[] combined = new byte[iv.length + ciphertext.length];
108	            System.arraycopy(iv, 0, combined, 0, iv.length);
109	            System.arraycopy(ciphertext, 0, combined, iv.length, ciphertext.length);
110	            return combined;
111	        } catch (Exception e) {
112	            throw new RuntimeException("Byte encryption failed", e);
113	        }
114	    }
115	
116	    /**
117	     * Decrypts raw bytes (IV prepended). Returns plaintext bytes.
118	     */
119	    public byte[] decryptBytes(byte[] encryptedBytes) {
120	        if (encryptedBytes == null) return null;
121	        try {
122	            byte[] iv = new byte[GCM_IV_LENGTH];
123	            byte[] ciphertext = new byte[encryptedBytes.length - GCM_IV_LENGTH];
124	            System.arraycopy(encryptedBytes, 0, iv, 0, GCM_IV_LENGTH);
125	            System.arraycopy(encryptedBytes, GCM_IV_LENGTH, ciphertext, 0, ciphertext.length);
126	
127	            Cipher cipher = Cipher.getInstance(ALGORITHM);
128	            cipher.init(Cipher.DECRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
129	            return cipher.doFinal(ciphertext);
130	        } catch (Exception e) {
131	            throw new RuntimeException("Byte decryption failed", e);
132	        }
133	    }
134	}
