163	    public Map<String, Object> getDataQuality(String domain, LocalDateTime from, LocalDateTime to) {
164	        Map<String, Object> quality = new LinkedHashMap<>();
165	
166	        if ("events".equals(domain) || domain == null) {
167	            quality.put("events_missing_description", countNullField("event", "description", from, to));
168	            quality.put("events_missing_location", countNullField("event", "location", from, to));
169	        }
170	
171	        if ("resources".equals(domain) || domain == null) {
172	            quality.put("resources_missing_description", countNullField("resource_item", "description", from, to));
173	        }
174	
175	        if ("rewards".equals(domain) || domain == null) {
176	            quality.put("rewards_missing_description", countNullField("reward_item", "description", from, to));
177	        }
178	
179	        // Duplicate detection counts
180	        if ("verification".equals(domain) || domain == null) {
181	            quality.put("credential_duplicates", countDuplicates(from, to));
182	        }
183	
184	        // Anomaly: accounts with excessive failed login attempts
185	        if ("accounts".equals(domain) || domain == null) {
186	            quality.put("accounts_with_high_failed_logins", countHighFailedLogins(from, to));
187	        }
188	
189	        return quality;
190	    }
