192	    private long countDuplicates(LocalDateTime from, LocalDateTime to) {
193	        String sql = "SELECT COUNT(*) FROM organization_credential_document " +
194	                "WHERE duplicate_flag = true AND created_at BETWEEN :from AND :to";
195	        Query query = entityManager.createNativeQuery(sql);
196	        query.setParameter("from", from);
197	        query.setParameter("to", to);
198	        return ((Number) query.getSingleResult()).longValue();
199	    }
200	
201	    private long countHighFailedLogins(LocalDateTime from, LocalDateTime to) {
202	        String sql = "SELECT COUNT(*) FROM account " +
203	                "WHERE failed_login_attempts >= 5 AND updated_at BETWEEN :from AND :to";
204	        Query query = entityManager.createNativeQuery(sql);
205	        query.setParameter("from", from);
206	        query.setParameter("to", to);
207	        return ((Number) query.getSingleResult()).longValue();
208	    }
