210	    private long countNullField(String table, String field, LocalDateTime from, LocalDateTime to) {
211	        String sql = "SELECT COUNT(*) FROM " + table +
212	                " WHERE " + field + " IS NULL AND created_at BETWEEN :from AND :to";
213	        Query query = entityManager.createNativeQuery(sql);
214	        query.setParameter("from", from);
215	        query.setParameter("to", to);
216	        return ((Number) query.getSingleResult()).longValue();
217	    }
