103	    @Transactional
104	    public AlertEventResult ingestEvent(String alertType, String scopeType, String scopeId,
105	                                         double measuredValue, String unit) {
106	        // Find applicable rule: override first, then default
107	        Optional<AlertRuleOverride> overrideOpt = overrideRepository
108	                .findByAlertTypeAndScopeTypeAndScopeId(alertType, scopeType, scopeId);
109	        Optional<AlertRuleDefault> defaultOpt = defaultRepository.findByAlertType(alertType);
110	
111	        String severity = "MEDIUM";
112	        double threshold = 0;
113	        String operator = "GT";
114	        int cooldownSeconds = 900;
115	        int durationSeconds = 0;
116	
117	        if (overrideOpt.isPresent()) {
118	            AlertRuleOverride override = overrideOpt.get();
119	            severity = override.getSeverity();
120	            threshold = override.getThresholdValue();
121	            operator = override.getThresholdOperator();
122	            cooldownSeconds = override.getCooldownSeconds();
123	            durationSeconds = override.getDurationSeconds();
124	        } else if (defaultOpt.isPresent()) {
125	            AlertRuleDefault def = defaultOpt.get();
126	            severity = def.getSeverity();
127	            threshold = def.getThresholdValue();
128	            operator = def.getThresholdOperator();
129	            cooldownSeconds = def.getCooldownSeconds();
130	            durationSeconds = def.getDurationSeconds();
131	        }
132	
133	        // Duration-window evaluation: if durationSeconds > 0, check that the condition
134	        // has persisted by verifying a prior threshold-exceeding event exists within the window.
135	        // If no prior event, this is the first occurrence — record but don't auto-create WO yet.
136	        boolean durationSatisfied = true;
137	        if (durationSeconds > 0 && thresholdExceeded(measuredValue, threshold, operator)) {
138	            LocalDateTime windowStart = LocalDateTime.now().minusSeconds(durationSeconds);
139	            long priorExceedances = alertEventRepository.countByAlertTypeAndScopeTypeAndScopeIdAndSuppressedFalseAndCreatedAtAfter(
140	                    alertType, scopeType, scopeId, windowStart);
141	            durationSatisfied = priorExceedances > 0;
142	        }
143	
144	        // Check cooldown
145	        LocalDateTime cooldownCutoff = LocalDateTime.now().minusSeconds(cooldownSeconds);
146	        Optional<AlertEvent> recentEvent = alertEventRepository.findLatestNonSuppressed(
147	                alertType, scopeType, scopeId, cooldownCutoff);
148	
149	        boolean suppressed = recentEvent.isPresent();
150	
151	        AlertEvent event = new AlertEvent();
152	        event.setAlertType(alertType);
153	        event.setScopeType(scopeType);
154	        event.setScopeId(scopeId);
155	        event.setSeverity(severity);
156	        event.setMeasuredValue(measuredValue);
157	        event.setMeasuredUnit(unit);
158	        event.setSuppressed(suppressed);
159	        event.setCreatedAt(LocalDateTime.now());
160	
161	        AlertEvent savedEvent = alertEventRepository.save(event);
162	
163	        WorkOrder workOrder = null;
164	
165	        // Auto-create work order if threshold exceeded, not suppressed, and duration satisfied
166	        if (!suppressed && thresholdExceeded(measuredValue, threshold, operator) && durationSatisfied) {
167	            workOrder = new WorkOrder();
168	            workOrder.setAlertEventId(savedEvent.getId());
169	            workOrder.setTitle("Alert: " + alertType + " [" + scopeType + ":" + scopeId + "]");
170	            workOrder.setDescription("Measured value " + measuredValue + " " + unit +
171	                    " exceeded threshold " + threshold);
172	            workOrder.setSeverity(severity);
173	            workOrder.setStatus("NEW_ALERT");
174	            workOrder.setCreatedBy(0L); // system
175	            workOrder.setCreatedAt(LocalDateTime.now());
176	            workOrder.setUpdatedAt(LocalDateTime.now());
177	            workOrder = workOrderRepository.save(workOrder);
178	
179	            auditService.log(0L, "SYSTEM", "WORK_ORDER_AUTO_CREATED",
180	                    "WorkOrder", workOrder.getId().toString(),
181	                    null, "NEW_ALERT", alertType, null);
182	        }
183	
184	        auditService.log(0L, "SYSTEM", "ALERT_EVENT_INGESTED",
185	                "AlertEvent", savedEvent.getId().toString(),
186	                null, suppressed ? "SUPPRESSED" : "ACTIVE", alertType, null);
187	
188	        return new AlertEventResult(savedEvent, workOrder);
189	    }
190	
191	    private boolean thresholdExceeded(double measured, double threshold, String operator) {
192	        return switch (operator) {
193	            case "GT" -> measured > threshold;
194	            case "GTE" -> measured >= threshold;
195	            case "LT" -> measured < threshold;
196	            case "LTE" -> measured <= threshold;
197	            case "EQ" -> measured == threshold;
198	            default -> measured > threshold;
199	        };
200	    }
201	
202	    public record AlertEventResult(AlertEvent alertEvent, WorkOrder workOrder) {}
203	}
