{"replace_all": false, "file_path": "/home/nico/Work/TASK-69/repo/backend/src/main/java/com/croh/alerts/AlertService.java", "old_string": "    private boolean thresholdExceeded(double measured, double threshold, String operator) {", "new_string": "    /**
     * Evaluates whether the threshold-exceeding condition has been sustained (unbroken)
     * for at least {@code durationSeconds}.
     *
     * <p>Retrieves all events for this alert type and scope within a lookback window of
     * {@code 2 * durationSeconds} (to capture the start of the current streak even if it
     * began slightly before the exact window). Then walks them chronologically:</p>
     * <ul>
     *   <li>Each event whose measured value exceeds the threshold extends the current streak.</li>
     *   <li>Each event whose measured value does NOT exceed the threshold resets the streak.</li>
     * </ul>
     *
     * <p>The duration is satisfied when the elapsed time from the start of the current
     * unbroken streak to now is {@code >= durationSeconds}.</p>
     *
     * @return true if the sustained exceedance streak meets or exceeds the required duration
     */
    private boolean evaluateSustainedDuration(String alertType, String scopeType, String scopeId,
                                               int durationSeconds, double threshold, String operator) {
        // Look back 2x duration to capture streak start even with timing jitter
        LocalDateTime lookback = LocalDateTime.now().minusSeconds((long) durationSeconds * 2);
        List<AlertEvent> recentEvents = alertEventRepository
                .findByAlertTypeAndScopeTypeAndScopeIdAndCreatedAtAfterOrderByCreatedAtAsc(
                        alertType, scopeType, scopeId, lookback);

        if (recentEvents.isEmpty()) {
            return false; // No prior events at all — first occurrence, duration not met
        }

        // Walk events chronologically to find the start of the current unbroken streak
        LocalDateTime streakStart = null;
        for (AlertEvent e : recentEvents) {
            if (thresholdExceeded(e.getMeasuredValue(), threshold, operator)) {
                // Threshold exceeded — start or continue streak
                if (streakStart == null) {
                    streakStart = e.getCreatedAt();
                }
            } else {
                // Threshold NOT exceeded — condition cleared, streak broken
                streakStart = null;
            }
        }

        if (streakStart == null) {
            return false; // No active streak (last event was below threshold)
        }

        // Duration satisfied if the unbroken streak started at least durationSeconds ago
        long streakDurationSeconds = java.time.Duration.between(streakStart, LocalDateTime.now()).getSeconds();
        return streakDurationSeconds >= durationSeconds;
    }

    private boolean thresholdExceeded(double measured, double threshold, String operator) {"}

