1	package com.croh.alerts;
2	
3	import com.croh.audit.AuditService;
4	import org.springframework.stereotype.Service;
5	import org.springframework.transaction.annotation.Transactional;
6	
7	import java.time.LocalDateTime;
8	import java.util.HashMap;
9	import java.util.List;
10	import java.util.Map;
11	import java.util.Optional;
12	
13	@Service
14	public class AlertService {
15	
16	    private final AlertRuleDefaultRepository defaultRepository;
17	    private final AlertRuleOverrideRepository overrideRepository;
18	    private final AlertEventRepository alertEventRepository;
19	    private final WorkOrderRepository workOrderRepository;
20	    private final AuditService auditService;
21	
22	    public AlertService(AlertRuleDefaultRepository defaultRepository,
23	                        AlertRuleOverrideRepository overrideRepository,
24	                        AlertEventRepository alertEventRepository,
25	                        WorkOrderRepository workOrderRepository,
26	                        AuditService auditService) {
27	        this.defaultRepository = defaultRepository;
28	        this.overrideRepository = overrideRepository;
29	        this.alertEventRepository = alertEventRepository;
30	        this.workOrderRepository = workOrderRepository;
31	        this.auditService = auditService;
32	    }
33	
34	    public Map<String, List<?>> getRules() {
35	        Map<String, List<?>> result = new HashMap<>();
36	        result.put("defaults", defaultRepository.findAll());
37	        result.put("overrides", overrideRepository.findAll());
38	        return result;
39	    }
40	
41	    @Transactional
42	    public AlertRuleDefault updateDefault(String alertType, String severity,
43	                                           String thresholdOperator, double thresholdValue,
44	                                           String thresholdUnit, int durationSeconds,
45	                                           int cooldownSeconds, Long actorId, String actorRole) {
46	        AlertRuleDefault rule = defaultRepository.findByAlertType(alertType)
47	                .orElseGet(() -> {
48	                    AlertRuleDefault newRule = new AlertRuleDefault();
49	                    newRule.setAlertType(alertType);
50	                    return newRule;
51	                });
52	
53	        rule.setSeverity(severity);
54	        rule.setThresholdOperator(thresholdOperator);
55	        rule.setThresholdValue(thresholdValue);
56	        rule.setThresholdUnit(thresholdUnit);
57	        rule.setDurationSeconds(durationSeconds);
58	        rule.setCooldownSeconds(cooldownSeconds);
59	        rule.setUpdatedAt(LocalDateTime.now());
60	
61	        AlertRuleDefault saved = defaultRepository.save(rule);
62	
63	        auditService.log(actorId, actorRole, "ALERT_RULE_DEFAULT_UPDATED",
64	                "AlertRuleDefault", saved.getId().toString(),
65	                null, null, alertType, null);
66	
67	        return saved;
68	    }
69	
70	    @Transactional
71	    public AlertRuleOverride updateOverride(String alertType, String scopeType, String scopeId,
72	                                             String severity, String thresholdOperator,
73	                                             double thresholdValue, String thresholdUnit,
74	                                             int durationSeconds, int cooldownSeconds,
75	                                             Long actorId, String actorRole) {
76	        AlertRuleOverride rule = overrideRepository
77	                .findByAlertTypeAndScopeTypeAndScopeId(alertType, scopeType, scopeId)
78	                .orElseGet(() -> {
79	                    AlertRuleOverride newRule = new AlertRuleOverride();
80	                    newRule.setAlertType(alertType);
81	                    newRule.setScopeType(scopeType);
82	                    newRule.setScopeId(scopeId);
83	                    return newRule;
84	                });
85	
86	        rule.setSeverity(severity);
87	        rule.setThresholdOperator(thresholdOperator);
88	        rule.setThresholdValue(thresholdValue);
89	        rule.setThresholdUnit(thresholdUnit);
90	        rule.setDurationSeconds(durationSeconds);
91	        rule.setCooldownSeconds(cooldownSeconds);
92	        rule.setUpdatedAt(LocalDateTime.now());
93	
94	        AlertRuleOverride saved = overrideRepository.save(rule);
95	
96	        auditService.log(actorId, actorRole, "ALERT_RULE_OVERRIDE_UPDATED",
97	                "AlertRuleOverride", saved.getId().toString(),
98	                null, null, alertType, null);
99	
100	        return saved;
101	    }
102	
103	    @Transactional
104	    public AlertEventResult ingestEvent(String alertType, String scopeType, String scopeId,
105	                                         double measuredValue, String unit) {
106	        // Find applicable rule: override first, then default
107	        Optional<AlertRuleOverride> overrideOpt = overrideRepository
108	                .findByAlertTypeAndScopeTypeAndScopeId(alertType, scopeType, scopeId);
109	        Optional<AlertRuleDefault> defaultOpt = defaultRepository.findByAlertType(alertType);
110	
111	        String severity = "MEDIUM";
112	        double threshold = 0;
113	        String operator = "GT";
114	        int cooldownSeconds = 900;
115	        int durationSeconds = 0;
116	
117	        if (overrideOpt.isPresent()) {
118	            AlertRuleOverride override = overrideOpt.get();
119	            severity = override.getSeverity();
120	            threshold = override.getThresholdValue();
121	            operator = override.getThresholdOperator();
122	            cooldownSeconds = override.getCooldownSeconds();
123	            durationSeconds = override.getDurationSeconds();
124	        } else if (defaultOpt.isPresent()) {
125	            AlertRuleDefault def = defaultOpt.get();
126	            severity = def.getSeverity();
127	            threshold = def.getThresholdValue();
128	            operator = def.getThresholdOperator();
129	            cooldownSeconds = def.getCooldownSeconds();
130	            durationSeconds = def.getDurationSeconds();
131	        }
132	
133	        // Duration-window evaluation for sustained-threshold semantics.
134	        //
135	        // When durationSeconds > 0, the threshold condition must have been SUSTAINED
136	        // (continuously exceeded) for at least that many seconds before a work order
137	        // is created. This models real sensor scenarios like "temperature > 120°F for
138	        // 5 continuous minutes."
139	        //
140	        // Algorithm:
141	        //   1. Find the earliest threshold-exceeding event for this alert/scope that
142	        //      occurred within a lookback window (2x durationSeconds for margin).
143	        //   2. Check whether the sustained exceedance streak is still intact: no
144	        //      event within the window recorded a value that did NOT exceed the threshold
145	        //      more recently than that earliest qualifying event (which would mean the
146	        //      condition cleared and restarted).
147	        //   3. The duration requirement is satisfied only when the current unbroken
148	        //      streak of threshold-exceeding events spans at least durationSeconds.
149	        //
150	        // If durationSeconds == 0, duration is trivially satisfied (immediate trigger).
151	        boolean durationSatisfied = true;
152	        final double evalThreshold = threshold;
153	        final String evalOperator = operator;
154	        if (durationSeconds > 0 && thresholdExceeded(measuredValue, threshold, operator)) {
155	            durationSatisfied = evaluateSustainedDuration(
156	                    alertType, scopeType, scopeId, durationSeconds, evalThreshold, evalOperator);
157	        }
158	
159	        // Check cooldown
160	        LocalDateTime cooldownCutoff = LocalDateTime.now().minusSeconds(cooldownSeconds);
161	        Optional<AlertEvent> recentEvent = alertEventRepository.findLatestNonSuppressed(
162	                alertType, scopeType, scopeId, cooldownCutoff);
163	
164	        boolean suppressed = recentEvent.isPresent();
165	
166	        AlertEvent event = new AlertEvent();
167	        event.setAlertType(alertType);
168	        event.setScopeType(scopeType);
169	        event.setScopeId(scopeId);
170	        event.setSeverity(severity);
171	        event.setMeasuredValue(measuredValue);
172	        event.setMeasuredUnit(unit);
173	        event.setSuppressed(suppressed);
174	        event.setCreatedAt(LocalDateTime.now());
175	
176	        AlertEvent savedEvent = alertEventRepository.save(event);
177	
178	        WorkOrder workOrder = null;
179	
180	        // Auto-create work order if threshold exceeded, not suppressed, and duration satisfied
181	        if (!suppressed && thresholdExceeded(measuredValue, threshold, operator) && durationSatisfied) {
182	            workOrder = new WorkOrder();
183	            workOrder.setAlertEventId(savedEvent.getId());
184	            workOrder.setTitle("Alert: " + alertType + " [" + scopeType + ":" + scopeId + "]");
185	            workOrder.setDescription("Measured value " + measuredValue + " " + unit +
186	                    " exceeded threshold " + threshold);
187	            workOrder.setSeverity(severity);
188	            workOrder.setStatus("NEW_ALERT");
189	            workOrder.setCreatedBy(0L); // system
190	            workOrder.setCreatedAt(LocalDateTime.now());
191	            workOrder.setUpdatedAt(LocalDateTime.now());
192	            workOrder = workOrderRepository.save(workOrder);
193	
194	            auditService.log(0L, "SYSTEM", "WORK_ORDER_AUTO_CREATED",
195	                    "WorkOrder", workOrder.getId().toString(),
196	                    null, "NEW_ALERT", alertType, null);
197	        }
198	
199	        auditService.log(0L, "SYSTEM", "ALERT_EVENT_INGESTED",
200	                "AlertEvent", savedEvent.getId().toString(),
201	                null, suppressed ? "SUPPRESSED" : "ACTIVE", alertType, null);
202	
203	        return new AlertEventResult(savedEvent, workOrder);
204	    }
205	
206	    /**
207	     * Evaluates whether the threshold-exceeding condition has been sustained (unbroken)
208	     * for at least {@code durationSeconds}.
209	     *
210	     * <p>Retrieves all events for this alert type and scope within a lookback window of
211	     * {@code 2 * durationSeconds} (to capture the start of the current streak even if it
212	     * began slightly before the exact window). Then walks them chronologically:</p>
213	     * <ul>
214	     *   <li>Each event whose measured value exceeds the threshold extends the current streak.</li>
215	     *   <li>Each event whose measured value does NOT exceed the threshold resets the streak.</li>
216	     * </ul>
217	     *
218	     * <p>The duration is satisfied when the elapsed time from the start of the current
219	     * unbroken streak to now is {@code >= durationSeconds}.</p>
220	     *
221	     * @return true if the sustained exceedance streak meets or exceeds the required duration
222	     */
223	    private boolean evaluateSustainedDuration(String alertType, String scopeType, String scopeId,
224	                                               int durationSeconds, double threshold, String operator) {
225	        // Look back 2x duration to capture streak start even with timing jitter
226	        LocalDateTime lookback = LocalDateTime.now().minusSeconds((long) durationSeconds * 2);
227	        List<AlertEvent> recentEvents = alertEventRepository
228	                .findByAlertTypeAndScopeTypeAndScopeIdAndCreatedAtAfterOrderByCreatedAtAsc(
229	                        alertType, scopeType, scopeId, lookback);
230	
231	        if (recentEvents.isEmpty()) {
232	            return false; // No prior events at all — first occurrence, duration not met
233	        }
234	
235	        // Walk events chronologically to find the start of the current unbroken streak
236	        LocalDateTime streakStart = null;
237	        for (AlertEvent e : recentEvents) {
238	            if (thresholdExceeded(e.getMeasuredValue(), threshold, operator)) {
239	                // Threshold exceeded — start or continue streak
240	                if (streakStart == null) {
241	                    streakStart = e.getCreatedAt();
242	                }
243	            } else {
244	                // Threshold NOT exceeded — condition cleared, streak broken
245	                streakStart = null;
246	            }
247	        }
248	
249	        if (streakStart == null) {
250	            return false; // No active streak (last event was below threshold)
251	        }
252	
253	        // Duration satisfied if the unbroken streak started at least durationSeconds ago
254	        long streakDurationSeconds = java.time.Duration.between(streakStart, LocalDateTime.now()).getSeconds();
255	        return streakDurationSeconds >= durationSeconds;
256	    }
257	
258	    private boolean thresholdExceeded(double measured, double threshold, String operator) {
259	        return switch (operator) {
260	            case "GT" -> measured > threshold;
261	            case "GTE" -> measured >= threshold;
262	            case "LT" -> measured < threshold;
263	            case "LTE" -> measured <= threshold;
264	            case "EQ" -> measured == threshold;
265	            default -> measured > threshold;
266	        };
267	    }
268	
269	    public record AlertEventResult(AlertEvent alertEvent, WorkOrder workOrder) {}
270	}
