     * Evaluates whether the threshold-exceeding condition has been sustained (unbroken)
     * for at least {@code durationSeconds}.
     *
     * <h3>Sustained-threshold duration model</h3>
     * <p>This implements the prompt's "configurable threshold duration window" as a
     * <strong>sustained-exceedance streak</strong>: the threshold must have been continuously
     * exceeded — with no intervening normal reading — for at least {@code durationSeconds}
     * before a work order is auto-created. This models real-world sensor scenarios like
     * "temperature &gt; 120°F for 5 continuous minutes before dispatching."</p>
     *
     * <h3>Algorithm (streak-walk)</h3>
     * <ol>
     *   <li>Query all events for this alert type + scope within a lookback window of
     *       {@code max(2 * durationSeconds, 3600)} seconds, ordered oldest-first.</li>
     *   <li>Walk chronologically. For each event:
     *       <ul>
     *         <li>If {@code thresholdExceeded(event.measuredValue)}: start a new streak
     *             (if none active) or continue the current one.</li>
     *         <li>If NOT exceeded: <strong>reset</strong> the streak — the condition cleared.</li>
     *       </ul></li>
     *   <li>After the walk, compute {@code streakSeconds = Duration(streakStart, now)}.</li>
     *   <li>Return {@code satisfied = (streakSeconds >= durationSeconds)}.</li>
     * </ol>
     *
     * <h3>Return value</h3>
     * <p>Returns a {@link DurationEvaluation} so callers and API responses can trace the
     * exact evaluation: streak start time, elapsed seconds, required seconds, and verdict.</p>
     */
    DurationEvaluation evaluateSustainedDuration(String alertType, String scopeType, String scopeId,
                                                  int durationSeconds, double threshold, String operator) {
        // Look back 2x duration (min 1 hour) to capture streak start with margin
        long lookbackSecs = Math.max((long) durationSeconds * 2, 3600);
        LocalDateTime lookback = LocalDateTime.now().minusSeconds(lookbackSecs);
        List<AlertEvent> recentEvents = alertEventRepository
                .findByAlertTypeAndScopeTypeAndScopeIdAndCreatedAtAfterOrderByCreatedAtAsc(
                        alertType, scopeType, scopeId, lookback);

        if (recentEvents.isEmpty()) {
            // No prior events — first occurrence, streak has zero history
            return new DurationEvaluation(false, null, 0, durationSeconds);
        }

        // Walk events chronologically to find the start of the current unbroken streak
        LocalDateTime streakStart = null;
        for (AlertEvent e : recentEvents) {
            if (thresholdExceeded(e.getMeasuredValue(), threshold, operator)) {
                // Threshold exceeded — begin or continue streak
                if (streakStart == null) {
                    streakStart = e.getCreatedAt();
                }
                // (if streakStart is already set, streak continues — no change)
            } else {
                // Threshold NOT exceeded — condition cleared, streak resets
                streakStart = null;
            }
        }

        if (streakStart == null) {
            // Most recent event was below threshold — no active streak
            return new DurationEvaluation(false, null, 0, durationSeconds);
        }

        long streakSeconds = java.time.Duration.between(streakStart, LocalDateTime.now()).getSeconds();
        boolean satisfied = streakSeconds >= durationSeconds;
        return new DurationEvaluation(satisfied, streakStart, streakSeconds, durationSeconds);
    }"}

