    @Test
    void noPriorEvents_returnsNotSatisfied() {
        AlertService.DurationEvaluation result = alertService.evaluateSustainedDuration(
                "TEMP", "STATION", "s1", 300, 100.0, "GT");

        assertFalse(result.satisfied());
        assertNull(result.streakStartedAt());
        assertEquals(0, result.streakSeconds());
        assertEquals(300, result.requiredSeconds());
    }

