        seedEvent("TEMP2", "STATION", "s2", 110, 400); // > 100, 400s ago

        AlertService.DurationEvaluation result = alertService.evaluateSustainedDuration(
                "TEMP2", "STATION", "s2", 300, 100.0, "GT");

        assertTrue(result.satisfied());
        assertNotNull(result.streakStartedAt());
        assertTrue(result.streakSeconds() >= 300,
                "Streak must span >= 300s, actual: " + result.streakSeconds());
        assertEquals(300, result.requiredSeconds());
    }

