103	    @Transactional
104	    public AlertEventResult ingestEvent(String alertType, String scopeType, String scopeId,
105	                                         double measuredValue, String unit) {
106	        // Find applicable rule: override first, then default
107	        Optional<AlertRuleOverride> overrideOpt = overrideRepository
108	                .findByAlertTypeAndScopeTypeAndScopeId(alertType, scopeType, scopeId);
109	        Optional<AlertRuleDefault> defaultOpt = defaultRepository.findByAlertType(alertType);
110	
111	        String severity = "MEDIUM";
112	        double threshold = 0;
113	        String operator = "GT";
114	        int cooldownSeconds = 900;
115	        int durationSeconds = 0;
116	
117	        if (overrideOpt.isPresent()) {
118	            AlertRuleOverride override = overrideOpt.get();
119	            severity = override.getSeverity();
120	            threshold = override.getThresholdValue();
121	            operator = override.getThresholdOperator();
122	            cooldownSeconds = override.getCooldownSeconds();
123	            durationSeconds = override.getDurationSeconds();
124	        } else if (defaultOpt.isPresent()) {
125	            AlertRuleDefault def = defaultOpt.get();
126	            severity = def.getSeverity();
127	            threshold = def.getThresholdValue();
128	            operator = def.getThresholdOperator();
129	            cooldownSeconds = def.getCooldownSeconds();
130	            durationSeconds = def.getDurationSeconds();
131	        }
132	
133	        // Duration-window evaluation for sustained-threshold semantics.
134	        //
135	        // When durationSeconds > 0, the threshold condition must have been SUSTAINED
136	        // (continuously exceeded) for at least that many seconds before a work order
137	        // is created. This models real sensor scenarios like "temperature > 120°F for
138	        // 5 continuous minutes."
139	        //
140	        // Algorithm:
141	        //   1. Find the earliest threshold-exceeding event for this alert/scope that
142	        //      occurred within a lookback window (2x durationSeconds for margin).
143	        //   2. Check whether the sustained exceedance streak is still intact: no
144	        //      event within the window recorded a value that did NOT exceed the threshold
145	        //      more recently than that earliest qualifying event (which would mean the
146	        //      condition cleared and restarted).
147	        //   3. The duration requirement is satisfied only when the current unbroken
148	        //      streak of threshold-exceeding events spans at least durationSeconds.
149	        //
150	        // If durationSeconds == 0, duration is trivially satisfied (immediate trigger).
151	        DurationEvaluation durationEval;
152	        final double evalThreshold = threshold;
153	        final String evalOperator = operator;
154	        if (durationSeconds == 0) {
155	            durationEval = DurationEvaluation.immediate();
156	        } else if (thresholdExceeded(measuredValue, threshold, operator)) {
157	            durationEval = evaluateSustainedDuration(
158	                    alertType, scopeType, scopeId, durationSeconds, evalThreshold, evalOperator);
159	        } else {
