161	            durationEval = new DurationEvaluation(false, null, 0, durationSeconds);
162	        }
163	
164	        // Check cooldown
165	        LocalDateTime cooldownCutoff = LocalDateTime.now().minusSeconds(cooldownSeconds);
166	        Optional<AlertEvent> recentEvent = alertEventRepository.findLatestNonSuppressed(
167	                alertType, scopeType, scopeId, cooldownCutoff);
168	
169	        boolean suppressed = recentEvent.isPresent();
170	
171	        AlertEvent event = new AlertEvent();
172	        event.setAlertType(alertType);
173	        event.setScopeType(scopeType);
174	        event.setScopeId(scopeId);
175	        event.setSeverity(severity);
176	        event.setMeasuredValue(measuredValue);
177	        event.setMeasuredUnit(unit);
178	        event.setSuppressed(suppressed);
179	        event.setCreatedAt(LocalDateTime.now());
180	
181	        AlertEvent savedEvent = alertEventRepository.save(event);
