186	        if (!suppressed && thresholdExceeded(measuredValue, threshold, operator) && durationEval.satisfied()) {
187	            workOrder = new WorkOrder();
188	            workOrder.setAlertEventId(savedEvent.getId());
189	            workOrder.setTitle("Alert: " + alertType + " [" + scopeType + ":" + scopeId + "]");
190	            workOrder.setDescription("Measured value " + measuredValue + " " + unit +
